1	/**
2	 * Content script on Google Calendar — the DOM layer of the hybrid model.
3	 *
4	 * It reads the open event surface (detail popover / expanded edit) to:
5	 *  - GATE the "Manage Visitors" button on the magic address being a guest,
6	 *  - capture the `data-eventid` (base64url "<eventId> <calendarId>"), and
7	 *  - take a best-effort SNAPSHOT (guest emails) so the panel can paint instantly
8	 *    and cover the unsaved (no-API) case.
9	 * The API layer (background) remains the authoritative source. We read only the
10	 * semantic `data-eventid`, the `[role="dialog"]` ARIA signal, and the surface's
11	 * visible text — no layout/CSS-class coupling, no injection into Google's markup.
12	 */
13	import { MAGIC_ADDRESS } from '@/lib/config';
14	import {
15	  ACTIVE_EID_KEY,
16	  ACTIVE_SNAPSHOT_KEY,
17	  NUDGE_TARGETS,
18	  PANEL_STATE,
19	} from '@/lib/messaging';
20	import type { DomEventSnapshot, VisitorEventSummary } from '@/lib/types';
21	
22	/** True while our extension context is still valid. After an extension reload or
23	 *  update, this content script is orphaned: every `chrome.*` call then throws
24	 *  "Extension context invalidated" (synchronously — `.catch()` can't see it). We
25	 *  check this before touching any chrome API so an orphan stops quietly. */
26	const extAlive = (): boolean => {
27	  try {
28	    return !!chrome.runtime?.id;
29	  } catch {
30	    return false;
31	  }
32	};
33	
34	/** sendMessage that never throws or rejects, even once the context is gone. */
35	function safeSend<T = unknown>(message: unknown): Promise<T | undefined> {
36	  if (!extAlive()) return Promise.resolve(undefined);
37	  try {
38	    return Promise.resolve(chrome.runtime.sendMessage(message)).catch(() => undefined);
39	  } catch {
40	    return Promise.resolve(undefined);
41	  }
42	}
43	
44	/** storage.session helpers that no-op once the context is gone. */
45	function safeStorageGet(key: string): Promise<Record<string, unknown>> {
46	  if (!extAlive()) return Promise.resolve({});
47	  try {
48	    return Promise.resolve(chrome.storage.session.get(key)).catch(() => ({}));
49	  } catch {
50	    return Promise.resolve({});
51	  }
52	}
53	function safeStorageSet(items: Record<string, unknown>): Promise<void> {
54	  if (!extAlive()) return Promise.resolve();
55	  try {
56	    return Promise.resolve(chrome.storage.session.set(items)).catch(() => {});
57	  } catch {
58	    return Promise.resolve();
59	  }
60	}
61	
62	export default defineContentScript({
63	  matches: ['https://calendar.google.com/*'],
64	  main() {
65	    // The id of the most recently clicked event chip — the event whose popover
66	    // is opening. Reset when the surface closes so a later unrelated dialog
67	    // can't resurrect a stale button.
68	    let clickedEid: string | null = null;
69	    let lastSnapshot: DomEventSnapshot | null = null;
70	    let panelOpen = false;
71	    let opening = false; // an OPEN_FOR_EVENT is in flight (panel not yet connected)
72	    let followedEid: string | null = null; // last event auto-pushed to the panel
73	    let pendingMagic: { eid: string; eventId: string; title: string } | null = null;
74	    let everSawEventId = false;
75	
76	    // Button UI: a native injected button when a clean anchor exists, else a
77	    // floating fallback (Idea 2). The magic-address gate is dropped — the button
78	    // shows on any open event surface; clicking it IS the intent.
79	    const button = createButtonUI(() => {
80	      if (!lastSnapshot) return;
81	      const snap = lastSnapshot;
82	      // Sanity guard: only OPEN the panel when it isn't already open (or
83	      // mid-open). If it's open, just point it at this event — clicking the
84	      // button again never fires a second sidePanel.open.
85	      if (panelOpen || opening) {
86	        followFor(snap);
87	      } else {
88	        opening = true;
89	        // Clear the latch if the panel never connects (open blocked/failed).
90	        setTimeout(() => {
91	          opening = false;
92	        }, 3000);
93	        openFor(snap); // opens the panel + sets the active event
94	      }
95	      // Note: we intentionally do NOT navigate the tab to the event here. The
96	      // panel resolves the event itself (Calendar API), so reloading the page
97	      // adds nothing but cost + surprise. "Open in Calendar" in the panel is the
98	      // explicit, user-initiated way to jump to the event.
99	    });
100	
101	    // In-page nudge banner: visitor events the user saved but hasn't acted on.
102	    // Driven by the background sync (robust), not live DOM scanning.
103	    const nudge = mountNudge();
104	    safeSend<{ ok?: boolean; data?: VisitorEventSummary[] }>({ type: 'GET_NUDGE_TARGETS' }).then(
105	      (res) => {
106	        if (res?.ok) nudge.setTargets(res.data as VisitorEventSummary[]);
107	      },
108	    );
109	
110	    // Seed the panel-open state on (re)load so auto-follow works after a
111	    // same-tab navigation (the panel persists; this content script is fresh).
112	    safeSend<{ ok?: boolean; data?: { open: boolean } }>({ type: 'GET_PANEL_STATE' }).then((res) => {
113	      if (res?.ok) {
114	        panelOpen = !!res.data?.open;
115	        nudge.setPanelOpen(panelOpen);
116	        render();
117	      }
118	    });
119	
120	    // Fast detection: sync on load, on tab focus, and right after leaving the
121	    // event editor (a likely save) — so the banner appears in seconds, not up
122	    // to a minute, and shows immediately when the user returns to the tab.
123	    let lastSync = 0;
124	    const syncNow = () => {
125	      const now = Date.now();
126	      if (now - lastSync < 4000) return; // throttle
127	      lastSync = now;
128	      safeSend({ type: 'SYNC_NOW' });
129	    };
130	    // Burst: fire several syncs after a likely save to beat Google's API
131	    // eventual-consistency lag (a fresh events.list may not show the just-saved
132	    // event for a few seconds).
133	    let lastBurst = 0;
134	    const syncBurst = () => {
135	      const now = Date.now();
136	      if (now - lastBurst < 2000) return;
137	      lastBurst = now;
138	      for (const d of [0, 3000, 8000]) {
139	        setTimeout(() => safeSend({ type: 'SYNC_NOW' }), d);
140	      }
141	    };
142	    syncNow();
143	    document.addEventListener('visibilitychange', () => {
144	      if (document.visibilityState === 'visible') syncNow();
145	    });
146	    window.addEventListener('focus', syncNow);
147	    let wasEditor = /\/eventedit/.test(location.pathname);
148	    const editorPoll = setInterval(() => {
149	      if (!extAlive()) return teardown(); // orphaned by an extension reload → stop
150	      const isEditor = /\/eventedit/.test(location.pathname);
151	      if (wasEditor && !isEditor) syncBurst(); // left the editor → likely saved
152	      wasEditor = isEditor;
153	      // Safety net: re-assert the button. The MutationObserver is debounced, so a
154	      // continuous scroll (which fires mutations faster than the debounce) can
155	      // starve it and never re-run render after Google re-renders the modal and
156	      // drops our injected button. This guarantees it comes back within ~1s.
157	      render();
158	    }, 1000);
159	
160	    // Stop all work once our context is invalidated (extension reloaded/updated),
161	    // so an orphaned script doesn't keep observing/polling — and remove our now-
162	    // dead button (its click can't reach the background) instead of leaving a
163	    // zombie that looks live but does nothing.
164	    let disposed = false;
165	    function teardown() {
166	      if (disposed) return;
167	      disposed = true;
168	      clearInterval(editorPoll);
169	      observer.disconnect();
170	      button.update(false);
171	    }
172	
173	    /** Read the open event surface, or null if none is open. `eid` may be '' for
174	     *  a brand-new, not-yet-saved event (no data-eventid / URL eid yet). */
175	    function readSurface(): { el: HTMLElement; eid: string } | null {
176	      const fromUrl = urlEid();
177	      const dialog = document.querySelector('[role="dialog"]') as HTMLElement | null;
178	      if (fromUrl) {
179	        return { el: dialog ?? document.body, eid: fromUrl };
180	      }
181	      // Full-screen create/edit editor. An existing event always carries its eid
182	      // in the URL (handled above), so reaching here means a brand-new, unsaved
183	      // event → eid ''. Never fall back to clickedEid: it can be stale from a
184	      // previously viewed event and would point the panel at the wrong one.
185	      if (/\/eventedit/.test(location.pathname)) {
186	        return { el: dialog ?? document.body, eid: '' };
187	      }
188	      // Detail / quick-create popover.
189	      if (dialog) return { el: dialog, eid: clickedEid ?? '' };
190	      return null;
191	    }
192	
193	    function snapshotOf(el: HTMLElement, eid: string): DomEventSnapshot {
194	      const text = el.innerText || '';
195	      const lower = text.toLowerCase();
196	      const magicPresent = !!MAGIC_ADDRESS && lower.includes(MAGIC_ADDRESS);
197	      const guestEmails = extractEmails(text).filter(
198	        (e) => e.toLowerCase() !== MAGIC_ADDRESS,
199	      );
200	      // Best-effort title (cosmetic — the API sync replaces it). The editor's
201	      // title is a text input; fall back to undefined.
202	      const titleInput = el.querySelector(
203	        'input[aria-label*="title" i], input[placeholder*="title" i]',
204	      ) as HTMLInputElement | null;
205	      const title = titleInput?.value?.trim() || undefined;
206	      return { eid, magicPresent, guestEmails, title };
207	    }
208	
209	    function render() {
210	      if (!extAlive()) return teardown(); // orphaned by an extension reload → stop
211	      const surface = readSurface();
212	      lastSnapshot = surface ? snapshotOf(surface.el, surface.eid) : null;
213	
214	      // Instant nudge: while viewing a visitor event WITH a real eid, remember
215	      // it; when the user then leaves that surface (closed popover / saved &
216	      // left editor), show the nudge for it IMMEDIATELY — no API round-trip.
217	      if (lastSnapshot?.magicPresent && lastSnapshot.eid) {
218	        pendingMagic = {
219	          eid: lastSnapshot.eid,
220	          eventId: decodeEventId(lastSnapshot.eid),
221	          title: lastSnapshot.title ?? '',
222	        };
223	      } else if (!surface && pendingMagic) {
224	        nudge.addOptimistic({
225	          eid: pendingMagic.eid,
226	          eventId: pendingMagic.eventId,
227	          iCalUid: '',
228	          title: pendingMagic.title,
229	          start: undefined,
230	        });
231	        syncBurst(); // confirm/refresh from the API right after
232	        pendingMagic = null;
233	      }
234	
235	      // Show the button on any open event surface — including while the panel
236	      // is open, so it stays available as an explicit "show this event" control.
237	      // Suppress the floating fallback while the panel is open: it's redundant
238	      // (auto-follow handles the viewed event) and would flash at the corner
239	      // while a navigated edit page is still loading.
240	      button.update(!!surface, !panelOpen);
241	      if (panelOpen) maybeFollow();
242	    }
243	
244	    /** Push the open *saved* event to the panel so it follows what you're viewing.
245	     *  Saved only (non-empty eid); deduped; the panel guards against switching
246	     *  mid-action. */
247	    function maybeFollow() {
248	      const snap = lastSnapshot;
249	      if (!snap || !snap.eid) return; // new/unsaved events don't auto-switch
250	      if (snap.eid === followedEid) return;
251	      followedEid = snap.eid;
252	      safeSend({ type: 'FOLLOW_EVENT', eid: snap.eid, snapshot: snap });
253	    }
254	
255	    document.addEventListener(
256	      'click',
257	      (e) => {
258	        const chip = (e.target as Element | null)?.closest?.('[data-eventid]');
259	        const id = chip?.getAttribute('data-eventid');
260	        if (id) {
261	          everSawEventId = true;
262	          clickedEid = id;
263	        }
264	        setTimeout(render, 60); // let the popover render
265	      },
266	      true,
267	    );
268	
269	    document.addEventListener(
270	      'keydown',
271	      (e) => {
272	        if (e.key === 'Escape') {
273	          clickedEid = null;
274	          setTimeout(render, 60);
275	        }
276	      },
277	      true,
278	    );
279	
280	    // Detect surface open/close + edits (e.g. adding the magic address live).
281	    let timer: number | undefined;
282	    const observer = new MutationObserver(() => {
283	      clearTimeout(timer);
284	      timer = setTimeout(() => {
285	        if (!document.querySelector('[role="dialog"]') && !urlEid()) {
286	          clickedEid = null;
287	        }
288	        render();
289	      }, 150) as unknown as number;
290	    });
291	    observer.observe(document.body, { childList: true, subtree: true });
292	
293	    window.addEventListener('popstate', render);
294	
295	    // Hide the in-page button while the side panel is open.
296	    chrome.runtime.onMessage.addListener(
297	      (msg: {
298	        type?: string;
299	        open?: boolean;
300	        targets?: VisitorEventSummary[];
301	        cancelled?: string[];
302	      }) => {
303	        if (msg?.type === PANEL_STATE) {
304	          panelOpen = !!msg.open;
305	          if (panelOpen) opening = false; // connected → clear the open latch
306	          if (!panelOpen) followedEid = null; // re-follow next time it opens
307	          nudge.setPanelOpen(panelOpen); // banner hides while the panel is open
308	          render();
309	        } else if (msg?.type === NUDGE_TARGETS) {
310	          nudge.setTargets(msg.targets ?? [], msg.cancelled ?? []);
311	        }
312	      },
313	    );
314	
315	    setTimeout(() => {
316	      if (!everSawEventId && !document.querySelector('[data-eventid]')) {
317	        console.warn(
318	          '[auxilio] no [data-eventid] found — click detection may be unavailable; use the panel’s event list.',
319	        );
320	      }
321	    }, 90_000);
322	
323	    render();
324	    console.log('[auxilio] content script ready on Google Calendar');
325	  },
326	});
327	
328	function openFor(snapshot: DomEventSnapshot) {
329	  return safeSend({ type: 'OPEN_FOR_EVENT', eid: snapshot.eid, snapshot });
330	}
331	
332	/** Point the already-open panel at an event without re-opening it. */
333	function followFor(snapshot: DomEventSnapshot) {
334	  return safeSend({ type: 'FOLLOW_EVENT', eid: snapshot.eid, snapshot });
335	}
336	
337	/** Event id from the expanded-edit URL path, if present. */
338	function urlEid(): string | null {
339	  const path = location.pathname.match(/\/eventedit\/([^/?#]+)/);
340	  if (path && path[1] !== 'eventedit') return safeDecode(path[1]);
341	  const q = new URLSearchParams(location.search).get('eid');
342	  return q ? safeDecode(q) : null;
343	}
344	
345	/** Pull unique email-looking strings from text (best-effort guest scrape). */
346	function extractEmails(text: string): string[] {
347	  const matches = text.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi) ?? [];
348	  return [...new Set(matches.map((m) => m.toLowerCase()))];
349	}
350	
351	/** eid (base64url of "<eventId> <calendarId>") → eventId, for nudge dedup. */
352	function decodeEventId(eid: string): string {
353	  try {
354	    let b64 = eid.replace(/-/g, '+').replace(/_/g, '/');
355	    b64 += '='.repeat((4 - (b64.length % 4)) % 4);
356	    return atob(b64).split(' ')[0] || '';
357	  } catch {
358	    return '';
359	  }
360	}
361	
362	function safeDecode(s: string): string {
363	  try {
364	    return decodeURIComponent(s);
365	  } catch {
366	    return s;
367	  }
368	}
369	
370	const USERS_SVG = `
371	<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24"
372	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
373	  <path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/>
374	  <path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>`;
375	
376	const LABEL = 'Manage Visitors';
377	const INJECT_ID = 'auxilio-manage-visitors';
378	
379	/**
380	 * Button UI manager: injects a native-styled "Manage Visitors" button as a real,
381	 * full-width row in the surface — below the Availability/Visibility section on the
382	 * edit page, at the bottom of the outermost content list in the detail popover (so
383	 * it scrolls with the rest of the UI, never an overlay) — and falls back to a
384	 * floating button only when no anchor is found. `update(show)` decides per render.
385	 */
386	function createButtonUI(onClick: () => void) {
387	  const fab = mountFloating(onClick);
388	  let injected: HTMLElement | null = null;
389	  let retryTimer: ReturnType<typeof setTimeout> | undefined;
390	
391	  // A clean injection anchor: where to drop the button + how far to indent it so
392	  // it lines up with the section's content column (past Google's icon gutter).
393	  // `inline` = sit next to a native button instead of as its own row.
394	  type Anchor = { insert: (el: HTMLElement) => void; inset: number; inline?: boolean };
395	
396	  /** Text/ARIA-based only — never CSS classes — so we stay decoupled from
397	   *  Google's obfuscated markup. Places the button where it reads as part of the
398	   *  form: between Description and the next section on the edit page, and as the
399	   *  last row of the detail popover's content list. Floating only as last resort. */
400	  function findAnchor(): Anchor | null {
401	    // Full-screen edit page → our own row just BELOW the Availability/Visibility
402	    // info section (falling back to above Description).
403	    if (/\/eventedit/.test(location.pathname)) {
404	      const avail = findAvailabilityInfo();
405	      const afterAvail = avail ? rowsListFor(avail) : null;
406	      if (afterAvail) {
407	        const { list, row } = afterAvail;
408	        return { insert: (el) => list.insertBefore(el, row.nextSibling), inset: rowInset(row, list) };
409	      }
410	      const desc = findEditDescription();
411	      const aboveDesc = desc ? rowsListFor(desc) : null;
412	      if (aboveDesc) {
413	        const { list, row } = aboveDesc;
414	        return { insert: (el) => list.insertBefore(el, row), inset: rowInset(row, list) };
415	      }
416	      // Fallback within the edit page: inline, right before the native "Save".
417	      const save = findButtonByText('save');
418	      const parent = save?.parentElement;
419	      if (save && parent) return { insert: (el) => parent.insertBefore(el, save), inset: 0, inline: true };
420	      return null;
421	    }
422	    // Detail popover / modal → BOTTOM of the OUTERMOST content list (after every
423	    // section, including the guest list). Robust whether or not guests exist.
424	    const dialog = document.querySelector<HTMLElement>('[role="dialog"]');
425	    if (dialog) {
426	      const list = findContentList(dialog);
427	      if (list) {
428	        const ref = firstIconLedRow(list);
429	        return { insert: (el) => list.appendChild(el), inset: ref ? rowInset(ref, list) : 0 };
430	      }
431	      // Fallback → bottom of the scrolling content.
432	      const scope = scrollContainer(dialog) ?? dialog;
433	      const l = mainVerticalList(scope) ?? scope;
434	      return { insert: (el) => l.appendChild(el), inset: 0 };
435	    }
436	    return null;
437	  }
438	
439	  function ensureInjected(): boolean {
440	    if (injected && injected.isConnected) return true; // still placed — skip the scan
441	    const anchor = findAnchor();
442	    if (!anchor) return false;
443	    removeInjected();
444	    ensureInjectedStyles();
445	    injected = anchor.inline
446	      ? buildInlineButton(onClick)
447	      : buildInjectedRow(onClick, anchor.inset);
448	    anchor.insert(injected);
449	    return true;
450	  }
451	
452	  function removeInjected() {
453	    injected?.remove();
454	    injected = null;
455	  }
456	
457	  return {
458	    // `allowFab` gates the floating fallback. It's only there to surface the
459	    // panel when we can't inject a native button; with the panel already open
460	    // it's redundant (auto-follow handles the viewed event), and it would flash
461	    // at the corner while a navigated page is still loading. So callers pass
462	    // false when the panel is open.
463	    update(show: boolean, allowFab = true) {
464	      clearTimeout(retryTimer);
465	      if (!show) {
466	        removeInjected();
467	        fab.setVisible(false);
468	        return;
469	      }
470	      // Try to inject now; if the anchor isn't in the DOM / laid out yet (Google
471	      // is still rendering the surface), keep retrying for a few seconds. The
472	      // MutationObserver covers DOM changes, but layout can settle — giving
473	      // elements their width — without a childList mutation, so width-based
474	      // anchor checks can miss that window. This retry guarantees we don't.
475	      let attempts = 0;
476	      const attempt = () => {
477	        const placed = ensureInjected();
478	        // Show the floating fallback only after a short grace period, so on a
479	        // normally-rendering surface the native button just appears — no flash
480	        // of the FAB getting replaced a moment later.
481	        fab.setVisible(allowFab && !placed && attempts >= 3);
482	        if (placed || attempts++ >= 30) return;
483	        retryTimer = setTimeout(attempt, 150);
484	      };
485	      attempt();
486	    },
487	  };
488	}
489	
490	/** Find a clickable element whose visible text matches (case-insensitive). */
491	function findButtonByText(text: string): HTMLElement | null {
492	  const wanted = text.toLowerCase();
493	  const els = document.querySelectorAll<HTMLElement>('button,[role="button"]');
494	  for (const el of els) {
495	    if ((el.textContent ?? '').trim().toLowerCase() === wanted) return el;
496	  }
497	  return null;
498	}
499	
500	const isVisible = (el: HTMLElement) => el.offsetParent !== null || el.getClientRects().length > 0;
501	
502	/** The Description editor on the event edit page. ARIA/placeholder text only —
503	 *  never CSS classes (Google's are obfuscated and churn). */
504	function findEditDescription(): HTMLElement | null {
505	  const els = document.querySelectorAll<HTMLElement>(
506	    '[aria-label*="description" i], [placeholder*="description" i]',
507	  );
508	  for (const el of els) if (isVisible(el)) return el;
509	  return null;
510	}
511	
512	/** The Availability/Visibility info block on the edit page. Prefers Google's
513	 *  stable `jsname` hook, falling back to the info text. */
514	function findAvailabilityInfo(): HTMLElement | null {
515	  const byJsname = document.querySelector<HTMLElement>('[jsname="g7cnnb"]');
516	  if (byJsname && isVisible(byJsname)) return byJsname;
517	  for (const el of document.querySelectorAll<HTMLElement>('span,div')) {
518	    const t = (el.textContent ?? '').trim().toLowerCase();
519	    if (t.startsWith('availability might be shown') && isVisible(el)) return el;
520	  }
521	  return null;
522	}
523	
524	/** The OUTERMOST rows list inside `root`: the shallowest container whose own
525	 *  children include several icon-led section rows. Breadth-first so a nested
526	 *  guest list never wins over the main content list. */
527	function findContentList(root: HTMLElement): HTMLElement | null {
528	  const queue: HTMLElement[] = [];
529	  for (const c of root.children) if (c instanceof HTMLElement) queue.push(c);
530	  while (queue.length) {
531	    const el = queue.shift()!;
532	    if (!isVisible(el)) continue;
533	    if (iconLedRowCount(el) >= 2) return el;
534	    for (const c of el.children) if (c instanceof HTMLElement) queue.push(c);
535	  }
536	  return null;
537	}
538	
539	/** The first wide icon-led row in a list — a reference for measuring the text
540	 *  column inset. */
541	function firstIconLedRow(list: HTMLElement): HTMLElement | null {
542	  const lw = list.getBoundingClientRect().width;
543	  for (const c of list.children) {
544	    if (!(c instanceof HTMLElement) || !isVisible(c) || !looksLikeRow(c)) continue;
545	    if (lw > 0 && c.getBoundingClientRect().width < lw * 0.5) continue;
546	    return c;
547	  }
548	  return null;
549	}
550	
551	/** Does this element stack its visible children vertically (a column of rows),
552	 *  rather than laying them out side by side? Geometry, not CSS classes. */
553	function stacksVertically(el: HTMLElement): boolean {
554	  const kids = [...el.children].filter((c): c is HTMLElement => c instanceof HTMLElement && isVisible(c));
555	  if (kids.length < 2) return false;
556	  for (let i = 1; i < kids.length; i++) {
557	    const a = kids[i - 1].getBoundingClientRect();
558	    const b = kids[i].getBoundingClientRect();
559	    if (b.top >= a.bottom - 2) return true; // the next child starts below the previous
560	  }
561	  return false;
562	}
563	
564	/** A native Calendar content row = a block whose first child is a decorative
565	 *  (aria-hidden) leading icon, followed by content. This is the one stable,
566	 *  class-free signal Google keeps across both the popover and the edit page. */
567	function looksLikeRow(el: HTMLElement): boolean {
568	  const first = el.firstElementChild;
569	  return (
570	    !!first &&
571	    el.childElementCount >= 2 &&
572	    (first.getAttribute('aria-hidden') === 'true' ||
573	      !!first.querySelector('svg, img, i.google-material-icons'))
574	  );
575	}
576	
577	/** How many of a container's visible children are icon-led *section* rows.
578	 *  Rows must span most of the container's width, which excludes narrow icon
579	 *  clusters like a description formatting toolbar. */
580	function iconLedRowCount(container: HTMLElement): number {
581	  const cw = container.getBoundingClientRect().width;
582	  let n = 0;
583	  for (const c of container.children) {
584	    if (!(c instanceof HTMLElement) || !isVisible(c) || !looksLikeRow(c)) continue;
585	    if (cw > 0 && c.getBoundingClientRect().width < cw * 0.5) continue; // skip toolbars/chips
586	    n++;
587	  }
588	  return n;
589	}
590	
591	/** From a field/label, climb to the rows list that holds it: the first ancestor
592	 *  whose parent contains several icon-led rows. Returns that list plus the row
593	 *  (a direct child of the list) that contains `el` — so we can insert relative
594	 *  to it. Null if no rows list is recognised. */
595	function rowsListFor(el: HTMLElement): { list: HTMLElement; row: HTMLElement } | null {
596	  let node: HTMLElement = el;
597	  while (node.parentElement && node.parentElement !== document.body) {
598	    const parent = node.parentElement;
599	    if (iconLedRowCount(parent) >= 2) return { list: parent, row: node };
600	    node = parent;
601	  }
602	  return null;
603	}
604	
605	/** The biggest vertically-stacking container inside `root` — the content column
606	 *  whose last child is the visual bottom of the surface. */
607	function mainVerticalList(root: HTMLElement): HTMLElement | null {
608	  let best: HTMLElement | null = null;
609	  let bestArea = 0;
610	  for (const el of root.querySelectorAll<HTMLElement>('*')) {
611	    if (!isVisible(el) || !stacksVertically(el)) continue;
612	    const r = el.getBoundingClientRect();
613	    const area = r.width * r.height;
614	    if (area > bestArea) {
615	      bestArea = area;
616	      best = el;
617	    }
618	  }
619	  return best;
620	}
621	
622	/** Left indent (px) that lines our button up with a native row's *text* column,
623	 *  past Google's leading icon gutter. Measured from where the row's first text
624	 *  actually paints, relative to the list we insert into. */
625	function rowInset(row: HTMLElement, list: HTMLElement): number {
626	  const gap = firstTextLeft(row) - list.getBoundingClientRect().left;
627	  return Number.isFinite(gap) && gap > 0 && gap < 240 ? Math.round(gap) : 0;
628	}
629	
630	/** Left edge of the first painted text inside `el` (skips the decorative icon
631	 *  gutter), or the element's own left if it has none. */
632	function firstTextLeft(el: HTMLElement): number {
633	  const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT);
634	  let node: Node | null;
635	  while ((node = walker.nextNode())) {
636	    if (!node.textContent || !node.textContent.trim()) continue;
637	    const range = document.createRange();
638	    range.selectNodeContents(node);
639	    const rect = range.getBoundingClientRect();
640	    if (rect.width > 0) return rect.left;
641	  }
642	  return el.getBoundingClientRect().left;
643	}
644	
645	/** The scrolling content region inside a surface (overflow-y auto/scroll),
646	 *  largest first — so our row lives with the content and scrolls, not in a
647	 *  pinned header/footer. Null when nothing scrolls. */
648	function scrollContainer(root: HTMLElement): HTMLElement | null {
649	  let best: HTMLElement | null = null;
650	  let bestArea = 0;
651	  for (const el of root.querySelectorAll<HTMLElement>('*')) {
652	    if (!isVisible(el)) continue;
653	    const oy = getComputedStyle(el).overflowY;
654	    if (oy !== 'auto' && oy !== 'scroll') continue;
655	    const r = el.getBoundingClientRect();
656	    const area = r.width * r.height;
657	    if (area > bestArea) {
658	      bestArea = area;
659	      best = el;
660	    }
661	  }
662	  return best;
663	}
664	
665	/** Stop our interactions dismissing Google's modal / triggering its buttons. */
666	function shieldInteractions(el: HTMLElement) {
667	  for (const type of ['pointerdown', 'mousedown', 'touchstart'] as const) {
668	    el.addEventListener(
669	      type,
670	      (e) => {
671	        e.stopPropagation();
672	        e.preventDefault(); // don't move focus out of the Calendar dialog
673	      },
674	      true,
675	    );
676	  }
677	  el.addEventListener('click', (e) => e.stopPropagation(), true);
678	}
679	
680	const STYLE_ID = 'auxilio-manage-visitors-style';
681	
682	/** One-time stylesheet for the injected (light-DOM) button. Styled to match a
683	 *  native Material outlined Calendar button — same shape, size, typography and
684	 *  hover state-layer — so it reads as part of Google's UI, just brand-tinted. */
685	function ensureInjectedStyles() {
686	  if (document.getElementById(STYLE_ID)) return;
687	  const s = document.createElement('style');
688	  s.id = STYLE_ID;
689	  s.textContent = `
690	    .auxilio-mv-row{box-sizing:border-box;display:flex;align-items:center;width:100%;padding:8px 0;}
691	    .auxilio-mv-btn{
692	      box-sizing:border-box;display:inline-flex;align-items:center;gap:8px;
693	      font-family:'Google Sans','Roboto',Arial,sans-serif;font-size:14px;font-weight:500;
694	      line-height:20px;letter-spacing:.25px;color:#92288e;background:transparent;
695	      border:1px solid #747775;border-radius:999px;padding:8px 18px 8px 14px;
696	      min-height:40px;cursor:pointer;white-space:nowrap;
697	      transition:background-color 120ms ease,border-color 120ms ease;
698	    }
699	    .auxilio-mv-btn:hover{background:rgba(146,40,142,.08);}
700	    .auxilio-mv-btn:active{background:rgba(146,40,142,.12);}
701	    .auxilio-mv-btn:focus-visible{outline:2px solid #92288e;outline-offset:2px;}
702	    .auxilio-mv-btn[disabled]{opacity:.6;cursor:default;}
703	    .auxilio-mv-btn svg{width:18px;height:18px;flex:0 0 auto;}
704	  `;
705	  document.documentElement.appendChild(s);
706	}
707	
708	/** The native-styled button itself (light DOM, classes from ensureInjectedStyles). */
709	function makeNativeButton(onClick: () => void): HTMLButtonElement {
710	  const btn = document.createElement('button');
711	  btn.type = 'button';
712	  btn.className = 'auxilio-mv-btn';
713	  btn.innerHTML = `${USERS_SVG}<span>${LABEL}</span>`;
714	  shieldInteractions(btn);
715	  wireActivate(btn, onClick);
716	  return btn;
717	}
718	
719	/** A full-width row carrying the button, indented to align with the section
720	 *  content column. Flows like a native section, so it can't overlap siblings. */
721	function buildInjectedRow(onClick: () => void, inset: number): HTMLElement {
722	  const row = document.createElement('div');
723	  row.id = INJECT_ID;
724	  row.className = 'auxilio-mv-row';
725	  if (inset) row.style.paddingLeft = `${inset}px`;
726	  row.appendChild(makeNativeButton(onClick));
727	  // Guard only the row's empty padding — clicks there must not dismiss Google's
728	  // surface; the button manages its own interactions (shieldInteractions).
729	  shieldPadding(row);
730	  return row;
731	}
732	
733	/** Inline button for the before-Save fallback (sits next to a native action). */
734	function buildInlineButton(onClick: () => void): HTMLButtonElement {
735	  const btn = makeNativeButton(onClick);
736	  btn.id = INJECT_ID;
737	  btn.style.marginRight = '8px';
738	  return btn;
739	}
740	
741	/** Stop interactions on the row's own padding (but not the button) from reaching
742	 *  Google — so an accidental tap beside the button can't close the dialog. */
743	function shieldPadding(row: HTMLElement) {
744	  const guard = (e: Event) => {
745	    if (e.target === row) {
746	      e.preventDefault();
747	      e.stopPropagation();
748	    }
749	  };
750	  for (const type of ['pointerdown', 'mousedown', 'touchstart', 'click'] as const) {
751	    row.addEventListener(type, guard, true);
752	  }
753	}
754	
755	/** Floating fallback button (shadow-DOM, fully isolated). */
756	function mountFloating(onClick: () => void) {
757	  const host = document.createElement('div');
758	  // pointer-events:none so the host box never eats clicks on what's beneath it when
759	  // the FAB is hidden — the inner button is display:inline-flex even when invisible, so
760	  // the host keeps a bounding box at bottom-right that would otherwise sit over (and
761	  // swallow clicks for) Google's own bottom drawer buttons (e.g. the event-edit add-on
762	  // drawer's "View"). The shown button re-enables hits via `.fab.show{pointer-events:auto}`.
763	  host.style.cssText = 'position:fixed;right:24px;bottom:24px;z-index:2147483646;pointer-events:none;';
764	  document.documentElement.appendChild(host);
765	  const root = host.attachShadow({ mode: 'open' });
766	  root.innerHTML = `
767	    <style>
768	      :host { all: initial; }
769	      .fab {
770	        display:inline-flex;align-items:center;gap:8px;
771	        font-family:'Google Sans','Roboto',system-ui,sans-serif;font-size:14px;font-weight:600;
772	        color:#fff;background:#92288e;border:none;border-radius:999px;padding:12px 18px;
773	        box-shadow:0 2px 6px rgba(0,0,0,.18);cursor:pointer;
774	        transform:translateY(8px);opacity:0;pointer-events:none;
775	        transition:opacity 200ms cubic-bezier(.2,0,0,1),transform 200ms cubic-bezier(.2,0,0,1),box-shadow 120ms ease;
776	      }
777	      .fab.show{opacity:1;transform:none;pointer-events:auto;}
778	      .fab:hover{box-shadow:0 4px 12px rgba(0,0,0,.24);}
779	      .fab:active{transform:scale(.98);}
780	      .fab[disabled]{opacity:.6;pointer-events:none;}
781	      @media (prefers-reduced-motion: reduce){.fab{transition:none;transform:none;}}
782	    </style>
783	    <button class="fab" type="button">${USERS_SVG}<span class="label">${LABEL}</span></button>`;
784	  const btn = root.querySelector('button') as HTMLButtonElement;
785	  shieldInteractions(host);
786	  wireActivate(btn, onClick);
787	  return {
788	    setVisible(v: boolean) {
789	      btn.classList.toggle('show', v);
790	    },
791	  };
792	}
793	
794	/** Shared activate handler (pointerup + click, double-fire-guarded). */
795	function wireActivate(btn: HTMLButtonElement, onClick: () => void) {
796	  const label = btn.querySelector('span:last-of-type') as HTMLSpanElement | null;
797	  let firing = false;
798	  const activate = async () => {
799	    if (firing) return;
800	    firing = true;
801	    btn.disabled = true;
802	    const prev = label?.textContent;
803	    if (label) label.textContent = 'Opening…';
804	    try {
805	      await onClick();
806	    } finally {
807	      btn.disabled = false;
808	      if (label && prev) label.textContent = prev;
809	      firing = false;
810	    }
811	  };
812	  btn.addEventListener('pointerup', activate);
813	  btn.addEventListener('click', activate);
814	}
815	
816	const NUDGE_DISMISS_KEY = 'auxilio.dismissedNudges';
817	const BELL_SVG = `
818	<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24"
819	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
820	  <path d="M10.268 21a2 2 0 0 0 3.464 0"/><path d="M3.262 15.326A1 1 0 0 0 4 17h16a1 1 0 0 0 .74-1.673C19.41 13.956 18 12.499 18 8A6 6 0 0 0 6 8c0 4.499-1.411 5.956-2.738 7.326"/></svg>`;
821	const NUDGE_X_SVG = `
822	<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24"
823	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
824	  <path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>`;
825	
826	/**
827	 * In-page nudge banner (sync-driven). Shows the soonest visitor event the user
828	 * saved but hasn't acted on. "Manage" opens the panel AND navigates this tab to
829	 * the event — one click opens both. Dismissals persist in storage.session.
830	 */
831	function mountNudge() {
832	  const host = document.createElement('div');
833	  // pointer-events:none so the (always-present) host box doesn't swallow clicks on the
834	  // Calendar UI beneath it while the banner is hidden — the banner is display:flex even
835	  // when invisible, so the host keeps a box at top-center. `.banner.show{pointer-events:auto}`
836	  // restores hits when it's actually shown.
837	  host.style.cssText =
838	    'position:fixed;top:72px;left:50%;transform:translateX(-50%);z-index:2147483647;pointer-events:none;';
839	  document.documentElement.appendChild(host);
840	  const root = host.attachShadow({ mode: 'open' });
841	  root.innerHTML = `
842	    <style>
843	      :host { all: initial; }
844	      .banner {
845	        display:flex;align-items:center;gap:12px;max-width:520px;
846	        font-family:'Google Sans','Roboto',system-ui,sans-serif;color:#310031;
847	        background:#f8d9f5;border:1px solid #92288e33;border-radius:14px;
848	        padding:10px 12px 10px 16px;box-shadow:0 4px 12px rgba(0,0,0,.18);
849	        transform:translateY(-12px);opacity:0;pointer-events:none;
850	        transition:opacity 200ms cubic-bezier(.2,0,0,1),transform 200ms cubic-bezier(.2,0,0,1);
851	      }
852	      .banner.show{opacity:1;transform:none;pointer-events:auto;}
853	      .icon{display:inline-flex;color:#92288e;flex:0 0 auto;}
854	      .text{font-size:13.5px;line-height:18px;}
855	      .text b{font-weight:600;}
856	      .actions{display:flex;align-items:center;gap:4px;flex:0 0 auto;}
857	      .manage{font:inherit;font-size:13px;font-weight:600;color:#fff;background:#92288e;
858	        border:none;border-radius:999px;padding:8px 14px;cursor:pointer;}
859	      .manage:hover{box-shadow:0 2px 6px rgba(0,0,0,.2);}
860	      .dismiss{display:inline-flex;align-items:center;justify-content:center;width:30px;height:30px;
861	        border:none;border-radius:50%;background:transparent;color:#5f5560;cursor:pointer;}
862	      .dismiss:hover{background:#0000000f;}
863	      @media (prefers-reduced-motion: reduce){.banner{transition:none;transform:none;}}
864	    </style>
865	    <div class="banner">
866	      <span class="icon">${BELL_SVG}</span>
867	      <span class="text"></span>
868	      <span class="actions">
869	        <button class="manage" type="button">Manage</button>
870	        <button class="dismiss" type="button" aria-label="Dismiss">${NUDGE_X_SVG}</button>
871	      </span>
872	    </div>`;
873	  const wrap = root.querySelector('.banner') as HTMLDivElement;
874	  const text = root.querySelector('.text') as HTMLSpanElement;
875	  const manageBtn = root.querySelector('.manage') as HTMLButtonElement;
876	  const dismissBtn = root.querySelector('.dismiss') as HTMLButtonElement;
877	  shieldInteractions(host);
878	
879	  let targets: VisitorEventSummary[] = [];
880	  // Optimistic, DOM-derived targets shown INSTANTLY (no API wait) for an event
881	  // the user just interacted with; the API sync reconciles them by eventId.
882	  const optimistic = new Map<string, VisitorEventSummary>();
883	  // Each optimistic guess is provisional: if the sync never confirms it as a
884	  // real visitor event (e.g. the event was deleted, already handled, or the
885	  // magic address removed), it self-expires rather than lingering forever.
886	  const optimisticTimers = new Map<string, ReturnType<typeof setTimeout>>();
887	  const OPTIMISTIC_TTL = 12_000;
888	  const dropOptimistic = (eventId: string) => {
889	    const timer = optimisticTimers.get(eventId);
890	    if (timer) clearTimeout(timer);
891	    optimisticTimers.delete(eventId);
892	    optimistic.delete(eventId);
893	  };
894	  let panelOpen = false;
895	  let dismissed = new Set<string>();
896	  let current: VisitorEventSummary | null = null;
897	
898	  safeStorageGet(NUDGE_DISMISS_KEY).then((r) => {
899	    dismissed = new Set((r[NUDGE_DISMISS_KEY] as string[]) ?? []);
900	    render();
901	  });
902	
903	  /** Merged, deduped, soonest-first (synced target wins over optimistic). */
904	  function merged(): VisitorEventSummary[] {
905	    const byId = new Map<string, VisitorEventSummary>();
906	    for (const o of optimistic.values()) byId.set(o.eventId, o);
907	    for (const t of targets) byId.set(t.eventId, t); // synced data wins
908	    return [...byId.values()].sort((a, b) =>
909	      (a.start ?? '~').localeCompare(b.start ?? '~'),
910	    );
911	  }
912	
913	  function visible(): VisitorEventSummary | null {
914	    return merged().find((t) => !dismissed.has(t.eventId)) ?? null;
915	  }
916	
917	  function render() {
918	    const t = panelOpen ? null : visible();
919	    current = t;
920	    if (!t) {
921	      wrap.classList.remove('show');
922	      return;
923	    }
924	    const more = merged().filter((x) => !dismissed.has(x.eventId)).length - 1;
925	    text.innerHTML =
926	      `<b>Visitor event needs passes.</b> ${escapeText(t.title || '')}` +
927	      (more > 0 ? ` <span style="opacity:.7">+${more} more</span>` : '');
928	    wrap.classList.add('show');
929	  }
930	
931	  // Use pointerup (not click): the host's capture-phase shield — which stops our
932	  // interactions from dismissing Google's modal — would otherwise swallow click.
933	  manageBtn.addEventListener('pointerup', () => {
934	    if (!current) return;
935	    const target = current;
936	    manageBtn.disabled = true;
937	    manageBtn.textContent = 'Opening…';
938	    // Engaging with the event clears its nudge for the session, so it doesn't
939	    // reappear when the panel closes (or when the optimistic re-add fires).
940	    dismissed.add(target.eventId);
941	    safeStorageSet({ [NUDGE_DISMISS_KEY]: [...dismissed] });
942	    render(); // hide the banner now
943	    // Set the active event FIRST (storage.session, now content-accessible) so the
944	    // panel has it the moment it mounts — no dependence on message ordering.
945	    safeStorageSet({ [ACTIVE_EID_KEY]: target.eid, [ACTIVE_SNAPSHOT_KEY]: null });
946	    // Open the panel within this gesture. We don't navigate the tab — the panel
947	    // resolves the event on its own; "Open in Calendar" there is the explicit way
948	    // to jump to it.
949	    safeSend({ type: 'OPEN_FOR_EVENT', eid: target.eid }).finally(() => {
950	      manageBtn.disabled = false;
951	      manageBtn.textContent = 'Manage';
952	    });
953	  });
954	
955	  dismissBtn.addEventListener('pointerup', () => {
956	    if (!current) return;
957	    dismissed.add(current.eventId);
958	    safeStorageSet({ [NUDGE_DISMISS_KEY]: [...dismissed] });
959	    render();
960	  });
961	
962	  return {
963	    setTargets(next: VisitorEventSummary[], cancelled: string[] = []) {
964	      targets = next ?? [];
965	      // The sync authoritatively resolved these away (deleted/cancelled/no
966	      // longer a visitor event) → purge any optimistic guess so a deleted
967	      // event can't keep nudging (or reopen the panel for a ghost event).
968	      for (const id of cancelled) dropOptimistic(id);
969	      // Drop optimistic entries the real sync now covers.
970	      for (const t of targets) dropOptimistic(t.eventId);
971	      render();
972	    },
973	    addOptimistic(s: VisitorEventSummary) {
974	      optimistic.set(s.eventId, s);
975	      const existing = optimisticTimers.get(s.eventId);
976	      if (existing) clearTimeout(existing);
977	      optimisticTimers.set(
978	        s.eventId,
979	        setTimeout(() => {
980	          optimistic.delete(s.eventId);
981	          optimisticTimers.delete(s.eventId);
982	          render();
983	        }, OPTIMISTIC_TTL),
984	      );
985	      render();
986	    },
987	    setPanelOpen(open: boolean) {
988	      panelOpen = open;
989	      render();
990	    },
991	  };
992	}
993	
994	function escapeText(s: string): string {
995	  const d = document.createElement('div');
996	  d.textContent = s;
997	  return d.innerHTML;
998	}
