}
function safeStorageSet(items: Record<string, unknown>): Promise<void> {
  if (!extAlive()) return Promise.resolve();
  try {
    return Promise.resolve(chrome.storage.session.set(items)).catch(() => {});
  } catch {
    return Promise.resolve();
