202	      onSuccess: (d) => setPreviewData({ preview: d, recipient: reviewEmail }),
203	    });
204	  };
205	
206	  const canSend = (included.length > 0 || data.materialized) && !send.isPending;
207	  const reviewLabel = data.materialized ? 'Review & update passes' : 'Review & send passes';
208	
209	  return (
210	    <Shell onBack={back}>
211	      <div className="enter" style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
212	        <div
