308	          )}
309	        </section>
310	
311	        {/* Send result */}
312	        {send.isSuccess && <SendSummary result={send.data} />}
313	        {send.isError && (
314	          <div className="banner banner--error" role="alert">
315	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
316	            <span className="type-body">{(send.error as Error).message}</span>
317	          </div>
318	        )}
319	      </div>
320	
321	      {/* Sticky action bar */}
322	      <footer
323	        style={{
324	          padding: 'var(--space-md) var(--space-lg)',
325	          borderTop: '1px solid var(--color-outline-variant)',
326	          background: 'var(--color-surface-lowest)',
327	        }}
328	      >
329	        <Button
330	          block
331	          loading={preview.isPending}
