333	          icon={<Eye size={18} strokeWidth={2} />}
334	          onClick={openReview}
335	        >
336	          {preview.isPending
337	            ? 'Loading preview…'
338	            : `${reviewLabel}${included.length ? ` (${included.length})` : ''}`}
339	        </Button>
340	        {preview.isError && (
341	          <div className="type-label-sm" style={{ color: 'var(--color-error)', textAlign: 'center', marginTop: 6 }}>
342	            {(preview.error as Error).message}
343	          </div>
344	        )}
345	        {sentCount > 0 && !send.isPending && (
346	          <div className="type-label-sm text-muted" style={{ textAlign: 'center', marginTop: 6 }}>
347	            {sentCount} pass{sentCount > 1 ? 'es' : ''} already issued
348	          </div>
349	        )}
350	      </footer>
351	
352	      {previewData && (
353	        <PreviewSheet
354	          preview={previewData.preview}
355	          recipient={previewData.recipient}
356	          totalCount={included.length}
357	          sending={send.isPending}
358	          onSend={() =>
359	            send.mutate(undefined, { onSuccess: () => setPreviewData(null) })
360	          }
361	          onClose={() => setPreviewData(null)}
362	        />
363	      )}
364	    </Shell>
365	  );
366	}
367	
368	// ───────────────────────── sub-components ─────────────────────────
369	
370	function Shell({ children, onBack }: { children: React.ReactNode; onBack?: () => void }) {
371	  return (
372	    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minWidth: 320 }}>
373	      <header
374	        style={{
375	          display: 'flex',
376	          alignItems: 'center',
377	          gap: 'var(--space-sm)',
378	          padding: 'var(--space-md) var(--space-lg)',
379	          borderBottom: '1px solid var(--color-outline-variant)',
380	          flex: '0 0 auto',
381	        }}
382	      >
383	        {onBack ? (
384	          <IconButton label="Back to events" onClick={onBack}>
385	            <ArrowLeft size={20} strokeWidth={2} />
386	          </IconButton>
387	        ) : (
388	          <Logo size={26} />
389	        )}
390	        <span className="type-title">Auxilio Visitor</span>
391	        <span style={{ flex: 1 }} />
392	        <AccountMenu />
393	      </header>
394	      <div style={{ flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
395	        {children}
396	      </div>
397	    </div>
398	  );
399	}
400	
401	function LoadingState({ label }: { label: string }) {
402	  return (
403	    <div
404	      style={{
405	        flex: 1,
406	        display: 'flex',
407	        flexDirection: 'column',
408	        alignItems: 'center',
409	        justifyContent: 'center',
410	        gap: 'var(--space-md)',
411	        color: 'var(--color-on-surface-variant)',
412	      }}
413	    >
414	      <span className="spinner" style={{ width: 22, height: 22 }} />
415	      <span className="type-body">{label}</span>
416	    </div>
417	  );
418	}
419	
420	function RosterSkeleton({ title }: { title?: string }) {
421	  return (
422	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
423	      <Card style={{ display: 'grid', gap: 8 }}>
424	        <span className="type-title-lg">{title || 'Loading event…'}</span>
425	        <Skeleton width="60%" />
426	      </Card>
427	      <Card style={{ display: 'grid', gap: 'var(--space-lg)' }}>
428	        {[0, 1, 2].map((i) => (
429	          <div key={i} style={{ display: 'flex', gap: 'var(--space-md)', alignItems: 'center' }}>
430	            <Skeleton width={44} height={24} radius={999} />
431	            <div style={{ flex: 1, display: 'grid', gap: 6 }}>
432	              <Skeleton width="50%" />
433	              <Skeleton width="70%" height={12} />
434	            </div>
435	          </div>
436	        ))}
437	      </Card>
438	    </div>
439	  );
440	}
441	
442	function NoticeState({
443	  title,
444	  body,
445	  onRetry,
446	  guests,
447	}: {
448	  title: string;
449	  body: string;
450	  onRetry?: () => void;
451	  guests?: string[];
452	}) {
453	  return (
454	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-md)' }}>
455	      <Card style={{ display: 'grid', gap: 'var(--space-sm)', padding: 'var(--space-xl)' }}>
456	        <span className="type-title-lg">{title}</span>
457	        <span className="type-body text-muted">{body}</span>
458	        {onRetry && (
459	          <Button
460	            variant="tonal"
461	            icon={<RefreshCw size={16} strokeWidth={2} />}
462	            onClick={onRetry}
463	            style={{ justifySelf: 'start', marginTop: 'var(--space-xs)' }}
464	          >
465	            Check again
466	          </Button>
467	        )}
468	      </Card>
469	      {guests && guests.length > 0 && (
470	        <Card style={{ display: 'grid', gap: 'var(--space-xs)' }}>
471	          <span className="type-label-sm text-muted" style={{ textTransform: 'uppercase' }}>
472	            Guests detected on this event
473	          </span>
474	          {guests.map((g) => (
475	            <span key={g} className="type-body row__ellipsis">{g}</span>
476	          ))}
477	        </Card>
478	      )}
479	    </div>
480	  );
481	}
482	
483	function ErrorState({ message, onRetry }: { message: string; onRetry: () => void }) {
484	  return (
485	    <div style={{ padding: 'var(--space-lg)' }}>
486	      <div className="banner banner--error" role="alert" style={{ marginBottom: 'var(--space-md)' }}>
487	        <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
488	        <span className="type-body">{message}</span>
489	      </div>
490	      <Button variant="tonal" icon={<RefreshCw size={16} strokeWidth={2} />} onClick={onRetry}>
491	        Try again
492	      </Button>
493	    </div>
494	  );
495	}
496	
497	function SendSummary({
498	  result,
499	}: {
500	  result: import('@/lib/types').SendResponse;
501	}) {
502	  return (
503	    <div
504	      className="banner"
505	      role="status"
506	      aria-live="polite"
507	      style={{ background: 'var(--color-success-container)', color: 'var(--color-on-success-container)' }}
508	    >
509	      <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
510	      <div>
511	        <div className="type-label">
512	          {result.created.length > 0
513	            ? `${result.created.length} pass${result.created.length > 1 ? 'es' : ''} sent`
514	            : 'Passes updated'}
515	          {result.cancelled.length > 0 && ` · ${result.cancelled.length} cancelled`}
516	        </div>
517	        {result.failed.length > 0 && (
518	          <ul className="type-label-sm" style={{ margin: '4px 0 0', paddingLeft: 16 }}>
519	            {result.failed.map((f) => (
520	              <li key={f.visitorEmail}>
521	                {f.visitorEmail}: {f.reason}
522	              </li>
523	            ))}
524	          </ul>
525	        )}
526	      </div>
527	    </div>
528	  );
529	}
530	
531	function formatWhen(start: string, end?: string): string {
532	  const allDay = !start.includes('T');
533	  const s = new Date(start);
534	  const date = s.toLocaleDateString(undefined, { weekday: 'short', day: 'numeric', month: 'short' });
535	  if (allDay) return `${date} · All day`;
536	  const t = (d: Date) => d.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
537	  return end ? `${date} · ${t(s)}–${t(new Date(end))}` : `${date} · ${t(s)}`;
538	}
