function onSaveAndSend(e) {
  var iCalUid = e.parameters.iCalUid;
  // Toggles/names/phones were already persisted by onReviewSend on the ROSTER card.
  // This runs from the CONFIRM card, which has none of those widgets — re-running
  // patchFromForm_ here would read empty inputs and wipe every guest to include=false
  // (the "No changes / No pass" bug). Only the (optional) template picker lives here.
  patchTemplateFromForm_(iCalUid, e);
  // Re-resolve event times here and send them along: if the draft-open missed them
  // (flaky Events.get on a just-created event), the draft would have no start/end and
  // the send would fail with EVENT_TIME_MISSING. Passing fresh times lets the engine
  // self-correct the draft instead of forcing the host to reopen.
  var ev = loadEvent_(e);
  // Times come only from Calendar.Events.get (the payload has none). If we still can't
  // read them, say exactly why instead of the engine's generic message — `got=false`
  // means the API call itself failed (scope/Advanced-Service/permission, not a timing
  // blip); `got=true start=null` means the event genuinely has no start.
  if (!ev.start || !ev.end) {
    // A 'Not Found' from Calendar.Events.get means the event isn't saved/propagated
    // yet — the panel shows attendees from the payload, but the event record (the only
    // source of start/end) doesn't exist server-side. Tell the host plainly.
    if (ev.debug.indexOf('Not Found') >= 0 || !ev.gotEvent) {
      return notify_('Save the event first (click Save), then reopen this panel and send. The pass time comes from the saved event.');
    }
    return notify_('Could not read the event time. Diagnostic: ' + ev.debug);
  }
  var res = engineFetch_('/api/visitor/calendar/addon/send', 'POST', {
    iCalUid: iCalUid, start: ev.start, end: ev.end
  });
  var msg;
  if (res.code === 200) {
    var sent = (res.json.created || []).length;
    var cancelled = (res.json.cancelled || []).length;
    var failed = res.json.failed || [];
    if (failed.length) {
      // Surface WHY a pass couldn't be sent (most often: event time in the past)
      // instead of silently leaving the guest pending.
      var reason = (failed[0] && failed[0].reason) || 'could not be sent';
      msg = "Couldn't send " + failed.length + ' pass' + (failed.length > 1 ? 'es' : '') + ': ' + reason;
    } else {
      var parts = [];
      if (sent) parts.push(sent + ' sent');
      if (cancelled) parts.push(cancelled + ' cancelled');
      msg = parts.length ? ('Passes updated: ' + parts.join(', ') + '.') : 'No changes.';
    }
  } else if (res.code === 0) {
    msg = 'Can’t reach the engine — passes were not sent. Try again in a moment.';
  } else {
    msg = 'Update failed (' + res.code + ').';
  }
  // Re-render so the card switches to Manage mode and shows fresh statuses.
  return CardService.newActionResponseBuilder()
    .setNotification(CardService.newNotification().setText(msg))
    .setNavigation(CardService.newNavigation().updateCard(buildVisitorCard_(e)))
    .build();
}

